import test from "node:test";
import assert from "node:assert/strict";

import { AsyncSlotCache } from "../src/async-slot-cache.mjs";
import { CatalogService } from "../src/catalog-service.mjs";

test("a rejected load releases its slot for a later request", async () => {
  const cache = new AsyncSlotCache();
  const transient = new Error("backend reset");
  let attempts = 0;

  await assert.rejects(cache.get("catalog", async () => {
    attempts += 1;
    throw transient;
  }), (error) => error === transient);

  const recovered = await cache.get("catalog", async () => {
    attempts += 1;
    return { version: 2 };
  });

  assert.deepEqual(recovered, { version: 2 });
  assert.equal(attempts, 2);
  assert.equal(cache.peek("catalog"), recovered);
});

test("catalog service can recover on the next call after a transient rejection", async () => {
  let attempts = 0;
  const service = new CatalogService({
    cache: new AsyncSlotCache(),
    availableLocales: ["en"],
    async loadCatalog({ tenant, locale }) {
      attempts += 1;
      if (attempts === 1) {
        throw new Error("temporary source failure");
      }
      return { tenant, locale, revision: 9 };
    }
  });

  const request = { tenant: "recoverable", preferredLocales: ["en"] };
  await assert.rejects(service.getCatalog(request), /temporary source failure/);
  const catalog = await service.getCatalog(request);
  assert.deepEqual(catalog, { tenant: "recoverable", locale: "en", revision: 9 });
  assert.equal(attempts, 2);
});
